1	import Taro from "@tarojs/taro";
2	import { PRESET_DOMAINS } from "./utils";
3	
4	export interface Domain {
5	  name: string;
6	  icon: string;
7	  color: string;
8	}
9	
10	export const UNCATEGORIZED: Domain = {
11	  name: "未分类",
12	  icon: "📦",
13	  color: "#78716c",
14	};
15	
16	const STORAGE_KEY = "custom_domains";
17	
18	export function getDomains(): Domain[] {
19	  const merged: Domain[] = [...PRESET_DOMAINS];
20	  try {
21	    const raw = Taro.getStorageSync(STORAGE_KEY);
22	    if (raw) {
23	      const custom: Domain[] = JSON.parse(raw);
24	      for (const d of custom) {
25	        if (!merged.find((m) => m.name === d.name)) {
26	          merged.push(d);
27	        }
28	      }
29	    }
30	  } catch (_) {
31	    // storage 为空或解析失败，使用默认
32	  }
33	  merged.push(UNCATEGORIZED);
34	  return merged;
35	}
36	
37	export function saveDomains(domains: Domain[]): void {
38	  const custom = domains.filter(
39	    (d) =>
40	      d.name !== UNCATEGORIZED.name &&
41	      !PRESET_DOMAINS.find((p) => p.name === d.name)
42	  );
43	  try {
44	    Taro.setStorageSync(STORAGE_KEY, JSON.stringify(custom));
45	  } catch (_) {
46	    // QuotaExceededError 等，静默失败
47	  }
48	}
49	
50	export function resetDomains(): Domain[] {
51	  try {
52	    Taro.removeStorageSync(STORAGE_KEY);
53	  } catch (_) {
54	    // 忽略
55	  }
56	  return getDomains();
57	}
