1	import { useState } from "react";
2	import { View, Text, Input, Picker } from "@tarojs/components";
3	import { useDidShow, showModal, showToast } from "@tarojs/taro";
4	import { apiFetch } from "../../lib";
5	import { getDomains, saveDomains, Domain, UNCATEGORIZED } from "../../lib/domains";
6	import "./index.scss";
7	
8	const EMOJI_OPTIONS = [
9	  "💪", "📚", "✨", "💼", "🧠", "🏛️", "🌍", "🏠",
10	  "🎯", "🎨", "🎵", "✍️", "🧘", "🏃", "🍎", "💻",
11	  "📝", "🎬", "🗣️", "🧭", "🔬", "📊", "💡", "⭐",
12	];
13	
14	const COLOR_OPTIONS = [
15	  "#ef4444", "#3b82f6", "#ec4899", "#f59e0b",
16	  "#8b5cf6", "#10b981", "#06b6d4", "#78716c",
17	];
18	
19	interface Habit {
20	  id: string;
21	  title: string;
22	  description: string | null;
23	  domainId: string;
24	  unit: string;
25	  targetValue: number;
26	  frequency: string;
27	  isActive: boolean;
28	}
29	
30	export default function HabitsPage() {
31	  const [habits, setHabits] = useState<Habit[]>([]);
32	  const [loading, setLoading] = useState(true);
33	  const [showForm, setShowForm] = useState(false);
34	  const [editId, setEditId] = useState<string | null>(null);
35	  const [form, setForm] = useState({
36	    title: "", description: "", domainIdx: 0, unit: "次",
37	    targetValue: 1, frequency: "daily",
38	  });
39	
40	  // Domain management state
41	  const [showDomainManager, setShowDomainManager] = useState(false);
42	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
43	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "💪", color: "#ef4444" });
44	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
45	  const [saving, setSaving] = useState(false);
46	
47	  useDidShow(() => { fetchHabits(); });
48	
49	  async function fetchHabits() {
50	    try {
51	      setHabits(await apiFetch("/api/habits"));
52	    } catch (e: any) {
53	      console.error("[fetchHabits]", e);
54	      showToast({ title: "获取习惯列表失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
55	    }
56	    setLoading(false);
57	  }
58	
59	  function openNew() {
60	    setEditId(null);
61	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
62	    setShowForm(true);
63	  }
64	
65	  function openEdit(h: Habit) {
66	    setEditId(h.id);
67	    const domains = getDomains();
68	    const idx = domains.findIndex(d => d.name === h.domainId);
69	    setForm({
70	      title: h.title,
71	      description: h.description || "",
72	      domainIdx: idx >= 0 ? idx : domains.length - 1,
73	      unit: h.unit,
74	      targetValue: h.targetValue,
75	      frequency: h.frequency,
76	    });
77	    setShowForm(true);
78	  }
79	
80	  async function handleSave() {
81	    const domains = getDomains();
82	    if (form.domainIdx < 0 || form.domainIdx >= domains.length) {
83	      showToast({ title: "领域索引无效", icon: "none" });
84	      return;
85	    }
86	    setSaving(true);
87	    try {
88	      const body = { ...form, domainId: domains[form.domainIdx].name };
89	      if (editId) {
90	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
91	      } else {
92	        await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
93	      }
94	      setShowForm(false);
95	      fetchHabits();
96	    } catch (e: any) {
97	      console.error("[handleSave]", e);
98	      showToast({ title: "保存习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
99	    } finally {
100	      setSaving(false);
101	    }
102	  }
103	
104	  async function deleteHabit(id: string) {
105	    try {
106	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
107	      fetchHabits();
108	    } catch (e: any) {
109	      console.error("[deleteHabit]", e);
110	      showToast({ title: "删除习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
111	    }
112	  }
113	
114	  async function toggleActive(id: string, current: boolean) {
115	    try {
116	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
117	      fetchHabits();
118	    } catch (e: any) {
119	      console.error("[toggleActive]", e);
120	      showToast({ title: "操作失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
121	    }
122	  }
123	
124	  // ---- Domain management handlers ----
125	
126	  function openDomainManager() {
127	    setShowForm(false);
128	    setDomainManagerView("list");
129	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
130	    setEditingDomainName(null);
131	    setShowDomainManager(true);
132	  }
133	
134	  function openNewDomain() {
135	    setDomainForm({ name: "", icon: "💪", color: "#ef4444" });
136	    setDomainManagerView("new");
137	  }
138	
139	  function openEditDomain(domain: Domain) {
140	    setEditingDomainName(domain.name);
141	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
142	    setDomainManagerView("edit");
143	  }
144	
145	  async function handleDomainSave() {
146	    const name = domainForm.name.trim();
147	    if (!name) return;
148	
149	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
150	
151	    if (domainManagerView === "new") {
152	      if (userDomains.some(d => d.name === name)) {
153	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
154	        return;
155	      }
156	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
157	    } else if (domainManagerView === "edit") {
158	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
159	      if (idx === -1) return;
160	
161	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
162	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
163	        return;
164	      }
165	
166	      const oldName = userDomains[idx].name;
167	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
168	
169	      // If domain renamed, update all habits under old name
170	      if (name !== oldName) {
171	        try {
172	          await Promise.all(habits.filter(h => h.domainId === oldName).map(h =>
173	            apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) })
174	          ));
175	          fetchHabits();
176	        } catch (e: any) {
177	          console.error("[handleDomainSave-migrate]", e);
178	          showToast({ title: "迁移习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
179	          return;
180	        }
181	      }
182	    }
183	
184	    saveDomains(userDomains);
185	    setDomainManagerView("list");
186	    setEditingDomainName(null);
187	  }
188	
189	  async function handleDeleteDomain(domain: Domain) {
190	    const count = habits.filter(h => h.domainId === domain.name).length;
191	    const res = await showModal({
192	      title: "删除领域",
193	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
194	    });
195	
196	    if (!res.confirm) return;
197	
198	    setSaving(true);
199	    try {
200	      // Move habits to 未分类 first, then delete domain
201	      await Promise.all(habits.filter(h => h.domainId === domain.name).map(h =>
202	        apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) })
203	      ));
204	
205	      const userDomains = getDomains()
206	        .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
207	      saveDomains(userDomains);
208	
209	      fetchHabits();
210	    } catch (e: any) {
211	      console.error("[handleDeleteDomain]", e);
212	      showToast({ title: "删除领域失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
213	    } finally {
214	      setSaving(false);
215	    }
216	  }
217	
218	  const domains = getDomains();
219	
220	  return (
221	    <View className="page">
222	      <View className="page-header">
223	        <View>
224	          <Text className="page-title">习惯管理</Text>
225	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
226	        </View>
227	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
228	      </View>
229	
230	      {domains.map((domain) => {
231	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
232	        return (
233	          <View key={domain.name}>
234	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
235	            {domainHabits.map((habit) => (
236	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
237	                <View className="habit-info">
238	                  <Text className="habit-name">{habit.title}</Text>
239	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
240	                  <View className="habit-meta">
241	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
242	                    <Text> · </Text>
243	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
244	                  </View>
245	                </View>
246	                <View className="habit-actions">
247	                  <Text className={`action-btn ${saving ? "disabled" : ""}`} onClick={() => !saving && toggleActive(habit.id, habit.isActive)}>
248	                    {habit.isActive ? "停用" : "启用"}
249	                  </Text>
250	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
251	                  <Text className={`action-btn danger ${saving ? "disabled" : ""}`} onClick={() => !saving && deleteHabit(habit.id)}>删除</Text>
252	                </View>
253	              </View>
254	            ))}
255	          </View>
256	        );
257	      })}
258	
259	      <View className="domain-manager-entry" onClick={openDomainManager}>
260	        <View className="domain-manager-entry-bar" />
261	        <Text className="domain-manager-entry-text">管理分类</Text>
262	        <Text className="domain-manager-entry-arrow">&#8250;</Text>
263	      </View>
264	
265	      {!loading && habits.length === 0 && (
266	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
267	      )}
268	
269	      {/* ---- Habit Form Modal ---- */}
270	      {showForm && (
271	        <View className="modal-mask" onClick={() => setShowForm(false)}>
272	          <View className="modal" onClick={(e) => e.stopPropagation()}>
273	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
274	
275	            <View className="form-group">
276	              <Text className="form-label">名称</Text>
277	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => setForm({ ...form, title: e.detail.value })} />
278	            </View>
279	
280	            <View className="form-group">
281	              <Text className="form-label">描述</Text>
282	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => setForm({ ...form, description: e.detail.value })} />
283	            </View>
284	
285	            <View className="form-row">
286	              <View className="form-group flex-1">
287	                <Text className="form-label">领域</Text>
288	                <Picker mode="selector" range={domains.map(d => d.icon + " " + d.name)} value={form.domainIdx} onChange={(e) => setForm({ ...form, domainIdx: +e.detail.value })}>
289	                  <View className="form-picker">{domains[form.domainIdx].icon} {domains[form.domainIdx].name}</View>
290	                </Picker>
291	              </View>
292	              <View className="form-group flex-1">
293	                <Text className="form-label">频率</Text>
294	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] })}>
295	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
296	                </Picker>
297	              </View>
298	            </View>
299	
300	            <View className="form-row">
301	              <View className="form-group flex-1">
302	                <Text className="form-label">目标值</Text>
303	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => setForm({ ...form, targetValue: +e.detail.value || 1 })} />
304	              </View>
305	              <View className="form-group flex-1">
306	                <Text className="form-label">单位</Text>
307	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => setForm({ ...form, unit: e.detail.value })} />
308	              </View>
309	            </View>
310	
311	            <View className="form-buttons">
312	              <View className="btn-cancel" onClick={() => setShowForm(false)}><Text>取消</Text></View>
313	              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
314	            </View>
315	          </View>
316	        </View>
317	      )}
318	
319	      {/* ---- Domain Manager Modal ---- */}
320	      {showDomainManager && (
321	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
322	          <View className="modal" onClick={(e) => e.stopPropagation()}>
323	            <View className="domain-manager-accent" />
324	
325	            {/* List View */}
326	            {domainManagerView === "list" && (
327	              <>
328	                <View className="modal-header-row">
329	                  <Text className="modal-title">管理分类</Text>
330	                  <Text className="modal-add-btn" onClick={openNewDomain}>+ 新增</Text>
