332	
333	                {domains.map((domain) => {
334	                  const isSystem = domain.name === UNCATEGORIZED.name;
335	                  return (
336	                    <View key={domain.name} className="domain-item">
337	                      <View className="domain-item-bar" style={{ backgroundColor: domain.color }} />
338	                      <Text className="domain-item-icon">{domain.icon}</Text>
339	                      <Text className="domain-item-name">{domain.name}</Text>
340	                      {isSystem ? (
341	                        <Text className="domain-item-tag">系统</Text>
