345	                            <Text>&#9998;</Text>
346	                          </View>
347	                          <View className={`domain-item-action delete${saving ? " disabled" : ""}`} onClick={() => !saving && handleDeleteDomain(domain)}>
348	                            <Text>&#10005;</Text>
349	                          </View>
350	                        </View>
351	                      )}
352	                    </View>
353	                  );
354	                })}
355	
356	                <View className="domain-close-btn" onClick={() => setShowDomainManager(false)}>
357	                  <Text>关闭</Text>
358	                </View>
359	              </>
360	            )}
361	
362	            {/* New / Edit Form View */}
363	            {(domainManagerView === "new" || domainManagerView === "edit") && (
364	              <>
365	                <Text className="modal-title">{domainManagerView === "new" ? "新增分类" : "编辑分类"}</Text>
366	
367	                <View className="form-group">
368	                  <Text className="form-label">名称</Text>
369	                  <Input
370	                    className="form-input"
371	                    placeholder="分类名称"
372	                    value={domainForm.name}
373	                    onInput={(e) => setDomainForm({ ...domainForm, name: e.detail.value })}
374	                  />
375	                </View>
376	
377	                <View className="form-section">
378	                  <Text className="form-section-title">图标</Text>
379	                  <View className="emoji-picker-rows">
380	                    <View className="emoji-row">
381	                      {EMOJI_OPTIONS.slice(0, 12).map((emoji) => (
382	                        <View
383	                          key={emoji}
384	                          className={`emoji-pill ${domainForm.icon === emoji ? "selected" : ""}`}
385	                          onClick={() => setDomainForm({ ...domainForm, icon: emoji })}
386	                        >
387	                          <Text>{emoji}</Text>
388	                        </View>
389	                      ))}
390	                    </View>
391	                    <View className="emoji-row">
392	                      {EMOJI_OPTIONS.slice(12).map((emoji) => (
393	                        <View
394	                          key={emoji}
395	                          className={`emoji-pill ${domainForm.icon === emoji ? "selected" : ""}`}
396	                          onClick={() => setDomainForm({ ...domainForm, icon: emoji })}
397	                        >
398	                          <Text>{emoji}</Text>
399	                        </View>
400	                      ))}
401	                    </View>
402	                  </View>
403	                </View>
404	
405	                <View className="form-section">
406	                  <Text className="form-section-title">颜色</Text>
407	                  <View className="color-picker-grid">
408	                    {COLOR_OPTIONS.map((color) => (
409	                      <View
410	                        key={color}
411	                        className={`color-swatch ${domainForm.color === color ? "selected" : ""}`}
412	                        onClick={() => setDomainForm({ ...domainForm, color })}
413	                      >
414	                        <View className="color-swatch-inner" style={{ backgroundColor: color }} />
415	                      </View>
416	                    ))}
417	                  </View>
418	                </View>
419	
420	                <View className="form-buttons">
421	                  <View className="btn-cancel" onClick={() => setDomainManagerView("list")}><Text>取消</Text></View>
422	                  <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleDomainSave()}><Text>保存</Text></View>
423	                </View>
424	              </>
425	            )}
426	
427	          </View>
428	        </View>
429	      )}
430	    </View>
431	  );
432	}
