4	import { apiFetch, getToday } from "../../lib";
5	import "./index.scss";
6	
7	export default function ReviewPage() {
8	  const [form, setForm] = useState({ score: 3, summary: "", highlight: "", lowlight: "", userSupplement: "" });
9	  const [submitted, setSubmitted] = useState(false);
10	  const [aiFeedback, setAiFeedback] = useState("");
11	  const [review, setReview] = useState<any>(null);
12	  const [aiSummary, setAiSummary] = useState("");
13	  const [aiSummaryError, setAiSummaryError] = useState(false);
14	  const [summaryLoading, setSummaryLoading] = useState(true);
15	
16	  useDidShow(() => {
17	    const today = getToday();
18	
19	    // Fetch existing review
20	    apiFetch(`/api/review?date=${today}`).then((data) => {
21	      if (data?.id) {
22	        setReview(data);
23	        setForm({
24	          score: data.score,
25	          summary: data.summary || "",
26	          highlight: data.highlight || "",
27	          lowlight: data.lowlight || "",
28	          userSupplement: data.userSupplement || "",
29	        });
30	        setAiFeedback(data.aiFeedback || "");
